import datetime
import matplotlib.pyplot as plt
import pandas as pd

class Workout:
    def __init__(self, date, sport, duration, distance=None, calories=None, heart_rate_data=None, pace=None):
        self.date = date
        self.sport = sport
        self.duration = duration  # in minutes
        self.distance = distance  # in km
        self.calories = calories
        self.heart_rate_data = heart_rate_data  # list of (timestamp, bpm) tuples
        self.pace = pace #minutes per km

    def __repr__(self):
        return f"{self.date} - {self.sport} - {self.duration} mins"

class Nutrition:
    def __init__(self, date, calories, protein, carbs, fat):
        self.date = date
        self.calories = calories
        self.protein = protein
        self.carbs = carbs
        self.fat = fat

    def __repr__(self):
        return f"{self.date} - Calories: {self.calories}, Protein: {self.protein}, Carbs: {self.carbs}, Fat: {self.fat}"


class WorkoutTracker:
    def __init__(self):
        self.workouts = []
        self.nutrition_data = []

    def import_strava(self, strava_data):
        # Simulate importing from Strava (replace with actual API calls)
        for activity in strava_data:
            self.workouts.append(Workout(
                date=activity['date'],
                sport=activity['sport'],
                duration=activity['duration'],
                distance=activity['distance'],
                heart_rate_data=activity['heart_rate_data'],
                pace=activity['pace']
            ))

    def import_polar_flow(self, polar_data):
        # Simulate importing from Polar Flow (replace with actual API calls)
        for activity in polar_data:
            self.workouts.append(Workout(
                date=activity['date'],
                sport=activity['sport'],
                duration=activity['duration'],
                distance=activity['distance'],
                heart_rate_data=activity['heart_rate_data']
            ))

    def import_myfitnesspal(self, mfp_data):
        # Simulate importing from MyFitnessPal (replace with actual API calls)
        for entry in mfp_data:
            self.nutrition_data.append(Nutrition(
                date=entry['date'],
                calories=entry['calories'],
                protein=entry['protein'],
                carbs=entry['carbs'],
                fat=entry['fat']
            ))

    def filter_workouts_by_sport(self, sport):
        return [workout for workout in self.workouts if workout.sport == sport]

    def calculate_total_mileage(self, sport=None):
        if sport:
            workouts = self.filter_workouts_by_sport(sport)
        else:
            workouts = self.workouts
        return sum(workout.distance for workout in workouts if workout.distance is not None)

    def calculate_heart_rate_zones(self):
        # Example heart rate zones (adjust as needed)
        zones = {
            "Zone 1": (0, 120),  # Example: Light activity
            "Zone 2": (120, 140), # Example: Moderate activity
            "Zone 3": (140, 160), # Example: Hard activity
            "Zone 4": (160, 180), # Example: Very hard activity
            "Zone 5": (180, 220), # Example: Maximum effort
        }

        zone_times = {zone: 0 for zone in zones}

        for workout in self.workouts:
            if workout.heart_rate_data:
                for timestamp, bpm in workout.heart_rate_data:
                    for zone, (lower, upper) in zones.items():
                        if lower <= bpm < upper:
                            zone_times[zone] += 1  # Increment time in seconds (assuming 1 reading per second)

        # Convert to minutes
        for zone in zone_times:
            zone_times[zone] /= 60

        return zone_times

    def plot_progress(self, metric="mileage"):
        dates = [workout.date for workout in self.workouts]
        dates.sort()
        date_objects = [datetime.datetime.strptime(date, "%Y-%m-%d").date() for date in dates]
        if metric == "mileage":
            mileages = [workout.distance for workout in self.workouts]
            plt.plot(date_objects, mileages)
            plt.xlabel("Date")
            plt.ylabel("Mileage (km)")
            plt.title("Mileage Over Time")
            plt.grid(True)
            plt.show()
        elif metric == "pace":
            paces = [workout.pace for workout in self.workouts if workout.pace is not None]
            plt.plot(date_objects[:len(paces)], paces)
            plt.xlabel("Date")
            plt.ylabel("Pace (min/km)")
            plt.title("Pace Over Time")
            plt.grid(True)
            plt.show()
        else:
            print("Invalid metric. Choose 'mileage' or 'pace'.")

    def display_nutrition_summary(self):
        df = pd.DataFrame(self.nutrition_data)
        if not df.empty:
            df['date'] = pd.to_datetime(df['date'])
            df = df.set_index('date')
            print(df.groupby(pd.Grouper(freq='M'))[['calories', 'protein', 'carbs', 'fat']].sum())
        else:
            print("No nutrition data available.")


