class FitnessApp:
    def __init__(self):
        self.users = {}
        self.data_sources = {}  # {"strava": StravaAPI(), "polar": PolarAPI()}
        self.dashboards = {}

    def register_user(self, username, password):
        if username in self.users:
            return "Username already exists."
        self.users[username] = {"password": password, "data": []}
        self.dashboards[username] = {}
        return "User registered successfully."

    def login(self, username, password):
        if username in self.users and self.users[username]["password"] == password:
            return "Login successful."
        return "Invalid username or password."

    def add_data_source(self, source_name, api_object):
        self.data_sources[source_name] = api_object

    def import_data(self, username, source_name, data):
        if username not in self.users:
            return "User not found."
        if source_name not in self.data_sources:
            return "Data source not found."

        try:
            imported_data = self.data_sources[source_name].parse_data(data)
            self.users[username]["data"].extend(imported_data)
            return "Data imported successfully."
        except Exception as e:
            return f"Error importing data: {e}"

    def create_dashboard(self, username, dashboard_name, sports=None):
        if username not in self.users:
            return "User not found."
        self.dashboards[username][dashboard_name] = {"sports": sports if sports else [], "metrics": {}}
        return "Dashboard created successfully."

    def add_metric_to_dashboard(self, username, dashboard_name, metric_name, metric_type, sport=None):
        if username not in self.users:
            return "User not found."
        if dashboard_name not in self.dashboards[username]:
            return "Dashboard not found."

        if sport and sport not in self.dashboards[username][dashboard_name]["sports"]:
            return "Sport not in dashboard"

        self.dashboards[username][dashboard_name]["metrics"][metric_name] = {"type": metric_type, "sport": sport}
        return "Metric added to dashboard."

    def get_dashboard_data(self, username, dashboard_name):
        if username not in self.users:
            return "User not found."
        if dashboard_name not in self.dashboards[username]:
            return "Dashboard not found."

        dashboard = self.dashboards[username][dashboard_name]
        user_data = self.users[username]["data"]
        dashboard_data = {}

        for metric_name, metric_config in dashboard["metrics"].items():
            metric_type = metric_config["type"]
            sport = metric_config["sport"]

            filtered_data = user_data
            if sport:
                filtered_data = [d for d in user_data if d.get("sport") == sport]

            if metric_type == "total_distance":
                total_distance = sum([d.get("distance", 0) for d in filtered_data])
                dashboard_data[metric_name] = total_distance
            elif metric_type == "total_time":
                total_time = sum([d.get("duration", 0) for d in filtered_data])
                dashboard_data[metric_name] = total_time
            elif metric_type == "max_heart_rate":
                max_heart_rate = max([d.get("heart_rate", 0) for d in filtered_data], default=0)
                dashboard_data[metric_name] = max_heart_rate
            elif metric_type == "average_pace":
                total_distance = sum([d.get("distance", 0) for d in filtered_data])
                total_time = sum([d.get("duration", 0) for d in filtered_data])
                if total_distance > 0:
                    average_pace = total_time / total_distance
                    dashboard_data[metric_name] = average_pace
                else:
                    dashboard_data[metric_name] = 0
            elif metric_type == "heart_rate_zones":
                dashboard_data[metric_name] = self.calculate_heart_rate_zones(filtered_data)
            else:
                dashboard_data[metric_name] = "Unsupported metric type."

        return dashboard_data

    def calculate_heart_rate_zones(self, data):
        zones = {"zone1": 0, "zone2": 0, "zone3": 0, "zone4": 0, "zone5": 0}
        for activity in data:
            heart_rates = activity.get("heart_rate_data", [])
            total_time = activity.get("duration", 0)
            if not heart_rates:
                continue

            time_per_rate = total_time / len(heart_rates)
            for rate in heart_rates:
                if 50 <= rate <= 60:
                    zones["zone1"] += time_per_rate
                elif 60 < rate <= 70:
                    zones["zone2"] += time_per_rate
                elif 70 < rate <= 80:
                    zones["zone3"] += time_per_rate
                elif 80 < rate <= 90:
                    zones["zone4"] += time_per_rate
                elif rate > 90:
                    zones["zone5"] += time_per_rate
        return zones

    def get_advancement_data(self, username, sport=None, metric="distance"):
        if username not in self.users:
            return "User not found."

        user_data = self.users[username]["data"]
        if sport:
            user_data = [d for d in user_data if d.get("sport") == sport]

        if metric == "distance":
            total_distance = sum([d.get("distance", 0) for d in user_data])
            return {"total_distance": total_distance}
        elif metric == "tempo":
            # Calculate average tempo over all activities
            total_distance = sum([d.get("distance", 0) for d in user_data])
            total_time = sum([d.get("duration", 0) for d in user_data])
            if total_distance > 0:
                average_tempo = total_time / total_distance
                return {"average_tempo": average_tempo}
            else:
                return {"average_tempo": 0}
        else:
            return "Unsupported advancement metric."

