import datetime
import json
import random

class FitnessApp:
    def __init__(self):
        self.user_data = {}
        self.training_data = []
        self.nutritional_data = []
        self.connected_apps = {}

    def register_user(self, username, age, weight, height, fitness_goals):
        if username not in self.user_data:
            self.user_data[username] = {
                'age': age,
                'weight': weight,
                'height': height,
                'fitness_goals': fitness_goals,
                'dashboards': {}
            }
            print(f"User {username} registered successfully.")
        else:
            print(f"User {username} already exists.")

    def connect_app(self, username, app_name):
        if username in self.user_data:
            self.connected_apps[username] = app_name
            print(f"{app_name} connected for {username}")
        else:
            print("User not registered")

    def import_data(self, username, data_source, data):
        if username in self.user_data:
            if data_source == 'Strava' or data_source == 'Polar Flow':
                self.training_data.extend(self.parse_training_data(username, data_source, data))
                print(f"Training data imported from {data_source} for {username}.")
            elif data_source == 'MyFitnessPal':
                self.nutritional_data.extend(self.parse_nutritional_data(username, data))
                print(f"Nutritional data imported from {data_source} for {username}.")
            else:
                print("Unsupported data source.")
        else:
            print("User not registered.")

    def parse_training_data(self, username, data_source, data):
        parsed_data = []
        for item in data:
            parsed_item = {
                'username': username,
                'data_source': data_source,
                'activity_type': item.get('activity_type', 'Unknown'),
                'date': item.get('date', datetime.date.today().isoformat()),
                'duration': item.get('duration', 0),
                'distance': item.get('distance', 0),
                'average_heart_rate': item.get('average_heart_rate', None),
                'max_heart_rate': item.get('max_heart_rate', None),
                'heart_rate_zones': item.get('heart_rate_zones', {}),
                'calories_burned': item.get('calories_burned', 0)
            }
            parsed_data.append(parsed_item)
        return parsed_data

    def parse_nutritional_data(self, username, data):
        parsed_data = []
        for item in data:
            parsed_item = {
                'username': username,
                'date': item.get('date', datetime.date.today().isoformat()),
                'calories': item.get('calories', 0),
                'protein': item.get('protein', 0),
                'carbohydrates': item.get('carbohydrates', 0),
                'fat': item.get('fat', 0)
            }
            parsed_data.append(parsed_item)
        return parsed_data

    def create_dashboard(self, username, dashboard_name, sports):
        if username in self.user_data:
            self.user_data[username]['dashboards'][dashboard_name] = {
                'sports': sports,
                'total_kilometers': 0,
                'total_time': 0,
                'max_heart_rate': 0
            }
            print(f"Dashboard '{dashboard_name}' created for {username} with sports: {sports}")
        else:
            print("User not registered.")

    def update_dashboard_stats(self, username, dashboard_name):
        if username in self.user_data and dashboard_name in self.user_data[username]['dashboards']:
            dashboard = self.user_data[username]['dashboards'][dashboard_name]
            sports = dashboard['sports']
            total_kilometers = 0
            total_time = 0
            max_heart_rate = 0

            for training_session in self.training_data:
                if training_session['username'] == username and training_session['activity_type'] in sports:
                    total_kilometers += training_session['distance']
                    total_time += training_session['duration']
                    if training_session['max_heart_rate'] is not None:
                        max_heart_rate = max(max_heart_rate, training_session['max_heart_rate'])

            dashboard['total_kilometers'] = total_kilometers
            dashboard['total_time'] = total_time
            dashboard['max_heart_rate'] = max_heart_rate
            print(f"Dashboard '{dashboard_name}' updated for {username}.")
        else:
            print("User or dashboard not found.")

    def view_dashboard(self, username, dashboard_name):
        if username in self.user_data and dashboard_name in self.user_data[username]['dashboards']:
            dashboard = self.user_data[username]['dashboards'][dashboard_name]
            print(f"Dashboard: {dashboard_name} for {username}")
            print(f"  Sports: {dashboard['sports']}")
            print(f"  Total Kilometers: {dashboard['total_kilometers']}")
            print(f"  Total Time: {dashboard['total_time']} minutes")
            print(f"  Max Heart Rate: {dashboard['max_heart_rate']}")
        else:
            print("User or dashboard not found.")

    def analyze_heart_rate_zones(self, username, activity_type):
        heart_rate_data = []
        for training_session in self.training_data:
            if training_session['username'] == username and training_session['activity_type'] == activity_type and 'heart_rate_zones' in training_session:
                heart_rate_data.append(training_session['heart_rate_zones'])

        if not heart_rate_data:
            print(f"No heart rate data found for {username} in {activity_type}.")
            return

        # Combine heart rate zone data from all sessions
        combined_zones = {}
        for session_zones in heart_rate_data:
            for zone, duration in session_zones.items():
                combined_zones[zone] = combined_zones.get(zone, 0) + duration

        print(f"Heart Rate Zone Analysis for {username} in {activity_type}:")
        for zone, duration in combined_zones.items():
            print(f"  Zone {zone}: {duration} minutes")

    def calculate_advancement(self, username, mode='distance'):
        total_distance = 0
        fastest_tempo = float('inf')

        for training_session in self.training_data:
            if training_session['username'] == username:
                total_distance += training_session['distance']
                if training_session['duration'] > 0 and training_session['distance'] > 0:
                    tempo = training_session['duration'] / training_session['distance']  # minutes per km
                    fastest_tempo = min(fastest_tempo, tempo)

        if mode == 'distance':
            print(f"Advancement for {username} (Distance): Total distance covered: {total_distance} km")
        elif mode == 'tempo':
            if fastest_tempo == float('inf'):
                print(f"No tempo data available for {username}.")
            else:
                print(f"Advancement for {username} (Tempo): Fastest tempo achieved: {fastest_tempo:.2f} minutes per km")
        else:
            print("Invalid advancement mode. Choose 'distance' or 'tempo'.")

    def personalized_screen(self, username):
        if username not in self.user_data:
            print("User not registered.")
            return

        print(f"Personalized Screen for {username}:")

        # Display user information
        user_info = self.user_data[username]
        print(f"  Age: {user_info['age']}")
        print(f"  Weight: {user_info['weight']} kg")
        print(f"  Height: {user_info['height']} cm")
        print(f"  Fitness Goals: {user_info['fitness_goals']}")

        # Display recent training data (last 5 sessions)
        print("\n  Recent Training Sessions:")
        recent_sessions = [session for session in self.training_data if session['username'] == username][-5:]
        for session in recent_sessions:
            print(f"    {session['date']}: {session['activity_type']} - {session['distance']} km, {session['duration']} minutes")

        # Display nutritional information (last 7 days)
        print("\n  Recent Nutritional Intake (Last 7 Days):")
        today = datetime.date.today()
        for i in range(7):
            date = today - datetime.timedelta(days=i)
            date_str = date.isoformat()
            daily_intake = [item for item in self.nutritional_data if item['username'] == username and item['date'] == date_str]
            total_calories = sum(item['calories'] for item in daily_intake)
            print(f"    {date_str}: Calories - {total_calories}")

        # Display connected apps
        if username in self.connected_apps:
            print(f"\n  Connected App: {self.connected_apps[username]}")
        else:
            print("\n  No connected apps.")

